import { d3_max } from '../../../core/d3-constants';
import { getMarkerSizes } from '../../../utils/svg-symbols';
import { getKey } from './correction-parser-helpers';

export function markerCorrectionParser(encodeType, index, chart) {
    let key = getKey('marker', encodeType, index),
        operator = [],
        size = d3_max(getMarkerSizes(chart)),
        margin = size ? 0 : 0;

    operator.push({
        _type: 'marker',
        data: [1],
        size: size + margin,
        position: 0,
        key
    });

    return operator;
}
